<?php
if(!defined("IN_ESOTALK"))exit;class feed extends Controller{var $items=array();var $pubDate="";var $title="";var $description="";var $link="";function init(){global $language,$config,$messages;$this->esoTalk->view="feed.view.php";header("Content-type: text/xml; charset={$language["charset"]}");if($return=$this->callHook("init"))return;switch(@$_GET["q2"]){case "conversation":$conversationId=(int)$_GET["q3"];if(!$conversationId or !($conversation=$this->esoTalk->db->fetchAssoc("SELECT c.conversationId AS id, c.title AS title, c.slug AS slug, c.private AS private, c.posts AS posts, c.startMember AS startMember, c.lastActionTime AS lastActionTime, GROUP_CONCAT(t.tag ORDER BY t.tag ASC SEPARATOR ', ') AS tags FROM {$config["tablePrefix"]}conversations c LEFT JOIN {$config["tablePrefix"]}tags t USING (conversationId) WHERE c.conversationId=$conversationId GROUP BY c.conversationId")))$this->esoTalk->fatalError($messages["cannotViewConversation"]["message"]);if($conversation["private"] or $conversation["posts"]==0){if(isset($_SERVER["PHP_AUTH_USER"]))$this->esoTalk->login($_SERVER["PHP_AUTH_USER"],$_SERVER["PHP_AUTH_PW"]);if(!$this->esoTalk->user){header('WWW-Authenticate: Basic realm="esoTalk RSS feed"');header('HTTP/1.0 401 Unauthorized');$this->esoTalk->fatalError($messages["cannotViewConversation"]["message"]);}if(!($conversation["startMember"]==$this->esoTalk->user["memberId"] or ($conversation["posts"]>0 and (!$conversation["private"] or $this->esoTalk->db->result("SELECT allowed FROM {$config["tablePrefix"]}status WHERE conversationId=$conversationId AND (memberId={$this->esoTalk->user["memberId"]} OR memberId='{$this->esoTalk->user["account"]}')",0))))){$this->esoTalk->fatalError($messages["cannotViewConversation"]["message"]);}}$this->title="{$conversation["title"]} - {$config["forumTitle"]}";$this->link=$config["baseURL"].makeLink($conversation["id"],$conversation["slug"]);$this->description=$conversation["tags"];$this->pubDate=date("D, d M Y H:i:s O",$conversation["lastActionTime"]);$result=$this->esoTalk->db->query("SELECT postId, name, content, time FROM {$config["tablePrefix"]}posts INNER JOIN {$config["tablePrefix"]}members USING (memberId) WHERE conversationId={$conversation["id"]} AND deleteMember IS NULL ORDER BY time DESC LIMIT 20");while(list($id,$member,$content,$time)=$this->esoTalk->db->fetchRow($result)){$this->items[]=array("title"=>$member,"description"=>sanitize($this->format($content)),"link"=>$config["baseURL"].makeLink("post",$id),"date"=>date("D, d M Y H:i:s O",$time));}break;default:$result=$this->esoTalk->db->query("SELECT p.postId, c.title, m.name, p.content, p.time FROM {$config["tablePrefix"]}posts p LEFT JOIN {$config["tablePrefix"]}conversations c USING (conversationId) INNER JOIN {$config["tablePrefix"]}members m ON (m.memberId=p.memberId) WHERE c.private=0 AND c.posts>0 AND p.deleteMember IS NULL ORDER BY p.time DESC LIMIT 20");while(list($postId,$title,$member,$content,$time)=$this->esoTalk->db->fetchRow($result)){$this->items[]=array("title"=>"$member - $title","description"=>sanitize($this->format($content)),"link"=>$config["baseURL"].makeLink("post",$postId),"date"=>date("D, d M Y H:i:s O",$time));}$this->title="{$language["Recent posts"]} - {$config["forumTitle"]}";$this->link=$config["baseURL"];$this->pubDate=!empty($this->items[0])?$this->items[0]["date"]:"";}}function format($post){global $config,$language;$this->callHook("formatPost",array(&$post));$post=preg_replace("`(<a href='".str_replace("?","\?",makeLink("post","(\d+)"))."'[^>]*>)<\/a>`","$1{$language["go to this post"]}</a>",$post);$post=preg_replace("/<a([^>]*) href='(?!http|ftp|mailto)([^']*)'/i","<a$1 href='{$config["baseURL"]}$2'",$post);$post=preg_replace("/<img([^>]*) src='(?!http|ftp|mailto)([^']*)'/i","<img$1 src='{$config["baseURL"]}$2'",$post);return $post;}}?>
